// Extract session_id from query string and recording URL from body
const query = $input.first().json.query || {};
const body = $input.first().json.body || {};

return [{
  json: {
    session_id: query.session_id || body.CallSid || '',
    caller_number: body.From || '',
    business_number: body.To || '',
    recording_url: body.RecordingUrl || '',
    recording_sid: body.RecordingSid || '',
    call_status: body.CallStatus || '',
    digits: body.Digits || '',
    speech_result: body.SpeechResult || ''
  }
}];

// Handle case where there's no recording (silence / timeout)
const session = $input.first().json;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://your-n8n.com';
const sessionId = session.session_id;

// Count silence occurrences (would come from session store in production)
const silenceCount = 1; // Increment from session in production

let responseText;
let shouldEnd = false;

if (silenceCount === 1) {
  responseText = "I didn't quite catch that. Could you please repeat?";
} else if (silenceCount === 2) {
  responseText = "Hello? Are you still there? I'm here to help whenever you're ready.";
} else {
  responseText = "It seems like we're having trouble hearing each other. I'll send you a WhatsApp message so you can reach us easily. Thank you for calling!";
  shouldEnd = true;
}

let twiml;
if (shouldEnd) {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${responseText}</Say>
  <Hangup/>
</Response>`;
} else {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${responseText}</Say>
  <Record maxLength="15" timeout="3" playBeep="false" transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}" />
  <Say voice="Polly.Aditi" language="en-IN">I am still here.</Say>
  <Record maxLength="15" timeout="5" playBeep="false" transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}" />
</Response>`;
}

return [{
  json: {
    ...session,
    twiml_response: twiml,
    silence_detected: true,
    should_end_call: shouldEnd
  }
}];

const input = $input.first().json;
const results = input.results;

// Extract transcript
let transcript = '';
let detectedLang = 'en';
let confidence = 0;

try {
  const channel = results.channels[0];
  const alt = channel.alternatives[0];
  transcript = alt.transcript || '';
  confidence = alt.confidence || 0;
  detectedLang = channel.detected_language || 'en';
} catch (e) {
  transcript = '';
  confidence = 0;
}

// Normalize language code
const langNormalize = {
  'ta': 'ta', 'ta-IN': 'ta',
  'te': 'te', 'te-IN': 'te',
  'kn': 'kn', 'kn-IN': 'kn',
  'ml': 'ml', 'ml-IN': 'ml',
  'en': 'en', 'en-IN': 'en', 'en-US': 'en',
  'hi': 'hi', 'hi-IN': 'hi'
};

const langMap = {
  'ta': 'Tamil', 'te': 'Telugu', 'kn': 'Kannada',
  'ml': 'Malayalam', 'en': 'English', 'hi': 'Hindi'
};

const normalizedLang = langNormalize[detectedLang] || 'en';

return [{
  json: {
    caller_transcript: transcript,
    detected_language: normalizedLang,
    language_name: langMap[normalizedLang] || 'English',
    stt_confidence: confidence,
    is_empty: transcript.trim() === '',
    session_id: input.session_id || '',
    caller_number: input.caller_number || '',
    business_number: input.business_number || '',
    recording_url: input.recording_url || ''
  }
}];

const transcript = $input.first().json.caller_transcript;
const lower = transcript.toLowerCase();

// ─── Keyword-based emotion detection ───
const angerWords = ['worst','terrible','disgusting','pathetic','waste','cheat','fraud','angry','disappointed','unacceptable','ridiculous','horrible','damn','hell','useless'];
const urgencyWords = ['urgent','immediately','right now','emergency','asap','hurry','quickly','fast','tonight','today only','need now'];
const confusionWords = ['confused','don\'t understand','what do you mean','unclear','not sure','which one','huh','sorry what','come again'];
const happyWords = ['great','awesome','perfect','wonderful','amazing','excellent','fantastic','love it','thank you so much','brilliant'];
const escalationWords = ['manager','supervisor','human','real person','transfer','speak to someone','complaint','higher authority','your boss'];

let emotion = 'neutral';
let escalate = false;
let emotionConfidence = 0.5;

if (escalationWords.some(k => lower.includes(k))) {
  escalate = true;
  emotion = 'wants_escalation';
  emotionConfidence = 0.95;
} else if (angerWords.some(k => lower.includes(k))) {
  emotion = 'angry';
  emotionConfidence = 0.8;
} else if (urgencyWords.some(k => lower.includes(k))) {
  emotion = 'urgent';
  emotionConfidence = 0.8;
} else if (confusionWords.some(k => lower.includes(k))) {
  emotion = 'confused';
  emotionConfidence = 0.7;
} else if (happyWords.some(k => lower.includes(k))) {
  emotion = 'happy';
  emotionConfidence = 0.7;
}

// Boost anger detection for CAPS and exclamation marks
const exclamationCount = (transcript.match(/!/g) || []).length;
const capsRatio = (transcript.replace(/[^A-Z]/g, '').length) / Math.max(transcript.length, 1);
if (exclamationCount > 2 || capsRatio > 0.5) {
  if (emotion === 'neutral') emotion = 'frustrated';
  emotionConfidence = Math.min(emotionConfidence + 0.15, 1.0);
}

return [{
  json: {
    ...$input.first().json,
    emotion_state: emotion,
    emotion_confidence: emotionConfidence,
    needs_escalation: escalate
  }
}];

// Transfer call to human agent
const session = $input.first().json;
const escalationNumber = $env.ESCALATION_PHONE || '+919876543210';

const transferMessage = "I completely understand. Let me connect you with my colleague right away. Please hold for just a moment.";
const fallbackMessage = "I'm sorry, our team member is unavailable right now. We'll call you back within 15 minutes. Thank you for your patience.";

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${transferMessage}</Say>
  <Dial timeout="30" callerId="${session.business_number}">
    <Number>${escalationNumber}</Number>
  </Dial>
  <Say voice="Polly.Aditi" language="en-IN">${fallbackMessage}</Say>
</Response>`;

return [{
  json: {
    ...session,
    twiml_response: twiml,
    escalation_triggered: true
  }
}];

const input = $input.first().json;
const prevSession = input;

// Extract AI response text
let aiText = '';
try {
  aiText = input.content[0].text || '';
} catch (e) {
  aiText = 'I\'m sorry, I\'m having a brief moment. Could you repeat that?';
}

// Extract <data> block
let extractedData = {};
const dataMatch = aiText.match(/<data>([\s\S]*?)<\/data>/);
if (dataMatch) {
  try {
    extractedData = JSON.parse(dataMatch[1]);
  } catch (e) { /* parse failed, continue */ }
}

// Remove <data> block from spoken response
const spokenResponse = aiText.replace(/<data>[\s\S]*?<\/data>/g, '').trim();

// Check if booking is complete
const d = extractedData;
const bookingComplete = d.intent === 'booking' &&
  d.date && d.time && d.guests && d.name;

return [{
  json: {
    session_id: prevSession.session_id,
    caller_number: prevSession.caller_number,
    business_number: prevSession.business_number,
    detected_language: prevSession.detected_language,
    language_name: prevSession.language_name,
    emotion_state: prevSession.emotion_state,
    caller_transcript: prevSession.caller_transcript,
    ai_response: spokenResponse,
    extracted_data: extractedData,
    detected_intent: extractedData.intent || 'unknown',
    booking_complete: bookingComplete || false
  }
}];

// ═══ HUMANIZATION ENGINE ═══
// Makes AI responses sound natural and human-like

const session = $input.first().json;
const response = session.ai_response;
const emotion = session.emotion_state;

// ── Filler injection (60% chance, context-aware) ──
const fillers = {
  neutral: ['Sure!', 'Absolutely.', 'Of course.', 'Right.', 'Got it.'],
  thinking: ['Let me check...', 'One moment...', 'Let me see...', 'Hmm, let me look into that...'],
  empathy: ['I understand.', 'I hear you.', 'That makes sense.', 'I completely get it.']
};

let humanized = response;

if (Math.random() < 0.6) {
  let fillerSet;
  if (emotion === 'angry' || emotion === 'frustrated') {
    fillerSet = fillers.empathy;
  } else if (response.length > 120) {
    fillerSet = fillers.thinking;
  } else {
    fillerSet = fillers.neutral;
  }
  const filler = fillerSet[Math.floor(Math.random() * fillerSet.length)];
  humanized = filler + ' ' + humanized;
}

// ── SSML pause markers for natural rhythm ──
humanized = humanized.replace(/\. /g, '. <break time="300ms"/> ');
humanized = humanized.replace(/\? /g, '? <break time="400ms"/> ');
humanized = humanized.replace(/! /g, '! <break time="200ms"/> ');

// ── Speaking rate based on emotion ──
let speakRate = '100%';
if (emotion === 'urgent') speakRate = '115%';
if (emotion === 'angry' || emotion === 'frustrated') speakRate = '90%';
if (emotion === 'confused') speakRate = '85%';

// ── Response delay (simulates thinking) ──
const wordCount = response.split(' ').length;
let delayMs = Math.min(400 + (wordCount * 30), 1500);
if (emotion === 'urgent') delayMs = Math.max(delayMs - 300, 200);

return [{
  json: {
    ...session,
    ai_response_humanized: humanized,
    speak_rate: speakRate,
    response_delay_ms: delayMs
  }
}];

const session = $input.first().json;
const sessionId = session.session_id;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://your-n8n.com';
const shouldEndCall = session.should_end_call || false;

// Plain text fallback for TTS response
const spokenText = (session.ai_response || 'Sorry, could you repeat that?')
  .replace(/<[^>]*>/g, ''); // Strip any SSML tags for Polly fallback

let twiml;
if (shouldEndCall) {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${spokenText}</Say>
  <Hangup/>
</Response>`;
} else {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${spokenText}</Say>
  <Record
    maxLength="15"
    timeout="3"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
    recordingStatusCallback="${n8nBaseUrl}/webhook/voice-agent/recording-ready"
  />
  <Say voice="Polly.Aditi" language="en-IN">I am still here if you need anything.</Say>
  <Record
    maxLength="15"
    timeout="5"
    playBeep="false"
    transcribe="false"
    action="${n8nBaseUrl}/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
  />
</Response>`;
}

return [{
  json: {
    ...session,
    twiml_response: twiml
  }
}];
